	operand2 = strings.Trim(operand2, "'\"")

	switch {
	case precision <= 7:
		return executeOperation32V2(op, operand1, operand2)
	case precision <= 16:
		return executeOperation64V2(op, operand1, operand2)
	default:
		return executeOperation128V2(op, operand1, operand2)
	}
