// parseDecTestFile parses an IBM decTest file
func parseDecTestFile(filename string) ([]decTestCase, error) {
	file, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	var cases []decTestCase
	scanner := bufio.NewScanner(file)

	// Default context values
	rounding := "half_even"
	precision := 9
	maxExponent := 384
	minExponent := -383
	clamp := 0

	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())

		// Skip comments and empty lines
		if line == "" || strings.HasPrefix(line, "--") {
			continue
		}

		// Handle directives
		if strings.Contains(line, ":") {
			parts := strings.SplitN(line, ":", 2)
			directive := strings.ToLower(strings.TrimSpace(parts[0]))
			value := strings.TrimSpace(parts[1])

			switch directive {
			case "rounding":
				rounding = value
			case "precision":
				fmt.Sscanf(value, "%d", &precision)
			case "maxexponent":
				fmt.Sscanf(value, "%d", &maxExponent)
			case "minexponent":
				fmt.Sscanf(value, "%d", &minExponent)
			case "clamp":
				fmt.Sscanf(value, "%d", &clamp)
			case "version", "extended":
				// Ignore these for now
				continue
			}
			continue
		}

		// Parse test cases (format: id operation operand... -> result flags)
		if strings.Contains(line, "->") {
			parts := strings.Split(line, "->")
			if len(parts) != 2 {
				continue
			}

			leftPart := splitDecTestFields(parts[0])
			rightText := strings.TrimSpace(parts[1])
			if commentIdx := strings.Index(rightText, "--"); commentIdx >= 0 {
				rightText = strings.TrimSpace(rightText[:commentIdx])
			}
			rightPart := splitDecTestFields(rightText)

			if len(leftPart) < 2 || len(rightPart) < 1 {
				continue
			}

			tc := decTestCase{
				ID:           leftPart[0],
				Operation:    leftPart[1],
				Operands:     leftPart[2:],
				Result:       rightPart[0],
				RoundingMode: rounding,
				Precision:    precision,
				MaxExponent:  maxExponent,
				MinExponent:  minExponent,
				Clamp:        clamp,
			}

			// Extract flags
			if len(rightPart) > 1 {
				tc.Flags = rightPart[1:]
			}

			cases = append(cases, tc)
		}
	}

	return cases, scanner.Err()
}

// compareDecimalResults compares two decimal result strings with decTest rules
func compareDecimalResults(expected, actual string) bool {
	if normalizeDecimalResult(expected) == normalizeDecimalResult(actual) {
		return true
	}

	left, leftOK := parseComparableDecimal(expected)
	right, rightOK := parseComparableDecimal(actual)
	if !leftOK || !rightOK {
		return false
	}
	return comparableDecimalResultsEqual(left, right)
}

func comparableDecimalResultsEqual(left, right decTestComparableDecimal) bool {
	if left.special != right.special {
		return false
	}

	switch left.special {
	case decTestSpecialNone:
		if left.isZero || right.isZero {
			return left.isZero && right.isZero && left.sign == right.sign
		}
		return left.sign == right.sign && left.digits == right.digits && left.exponent == right.exponent
	case decTestSpecialInfinity:
		return left.sign == right.sign
	case decTestSpecialQuietNaN, decTestSpecialSignalingNaN:
		return left.nanSign == right.nanSign && left.payload == right.payload
	case decTestSpecialInvalidSyntax:
		return true
	default:
		return false
	}
}

// getBaseName returns the base name of a file
func getBaseName(filename string) string {
	base := strings.TrimSuffix(filename, ".decTest")
	lastSlash := strings.LastIndex(base, "/")
	if lastSlash != -1 {
		base = base[lastSlash+1:]
	}
	return base
}

func normalizeDecTestOperation(op string) string {
	op = strings.TrimSpace(strings.ToLower(op))
	return strings.ReplaceAll(op, "_", "")
}

