func unsupportedFMADecTestReason(tc decTestCase) (string, bool) {
	if normalizeDecTestOperation(tc.Operation) != "fma" {
		return "", false
	}
	if _, ok := decTestBIDRoundingMode(tc.RoundingMode); !ok {
		return "fma_unsupported_rounding", true
	}
	if isUnsupportedFMANaNPayloadPrecedenceCase(tc) {
		return "fma_nan_payload_precedence", true
	}
	if hasDecTestFlag(tc.Flags, "clamped") &&
		!hasDecTestFlag(tc.Flags, "underflow") &&
		!hasDecTestFlag(tc.Flags, "inexact") &&
		!hasDecTestFlag(tc.Flags, "overflow") {
		return "fma_clamped_status_gap", true
	}
	if hasDecTestFlag(tc.Flags, "rounded") && !hasDecTestFlag(tc.Flags, "inexact") {
		return "fma_rounded_only_status_gap", true
	}
	return "", false
}

