func unsupportedRemainderFamilyDecTestReason(tc decTestCase, operation string) (string, bool) {
	if normalizeDecTestOperation(tc.Operation) != operation {
		return "", false
	}
	if hasDecTestFlag(tc.Flags, "divisionimpossible") {
		return operation + "_division_impossible_status_gap", true
	}
	if hasDecTestFlag(tc.Flags, "clamped") {
		return operation + "_clamped_status_gap", true
	}
	if len(tc.Operands) == 2 && isQuietDecTestNaN(tc.Operands[0]) && isSignalingDecTestNaN(tc.Operands[1]) {
		return operation + "_nan_payload_precedence", true
	}
	return "", false
}

func isUnsupportedNextTowardNaNPayloadPrecedenceCase(tc decTestCase) bool {
	if normalizeDecTestOperation(tc.Operation) != "nexttoward" || len(tc.Operands) != 2 {
		return false
	}
	left := strings.ToLower(decTestOperandString(tc.Operands[0]))
	right := strings.ToLower(decTestOperandString(tc.Operands[1]))
	return strings.Contains(left, "nan") && hasDecTestNaNPayload(left) && strings.Contains(right, "snan")
}

func isUnsupportedMinMaxZeroTieCase(tc decTestCase) bool {
	if !isMinMaxDecTestOperation(tc.Operation) || len(tc.Operands) != 2 {
		return false
	}
	left, leftOK := parseComparableDecimal(tc.Operands[0])
	right, rightOK := parseComparableDecimal(tc.Operands[1])
	return leftOK && rightOK &&
		left.special == decTestSpecialNone && right.special == decTestSpecialNone &&
		left.isZero && right.isZero && left.sign != right.sign
}

func isUnsupportedMinMaxNaNPayloadPrecedenceCase(tc decTestCase) bool {
	if !isMinMaxDecTestOperation(tc.Operation) || len(tc.Operands) != 2 {
		return false
	}
	left := decTestOperandString(tc.Operands[0])
	right := decTestOperandString(tc.Operands[1])
	return isQuietDecTestNaN(left) && isSignalingDecTestNaN(right)
}

// isUnsupportedFMANaNPayloadPrecedenceCase reports fma cases where GDA decTest
// NaN propagation (first signaling NaN in operand order x, y, z; otherwise the
// first quiet NaN) selects a different NaN identity (sign plus payload) than
// the Intel BID port, which propagates the first NaN it unpacks in y, z, x
// order (bid-go fma64/bid128_fma NaN unpack order). When both rules pick the
// same identity the case runs; only genuinely divergent identities are skipped.
func isUnsupportedFMANaNPayloadPrecedenceCase(tc decTestCase) bool {
	if len(tc.Operands) != 3 {
		return false
	}
	var infos [3]decTestNaNOperand
	for i := range tc.Operands {
		infos[i] = parseDecTestNaNOperand(tc.Operands[i])
	}
	gda := -1
	for i := range infos {
		if infos[i].isNaN && infos[i].signaling {
			gda = i
			break
		}
	}
	if gda < 0 {
		for i := range infos {
			if infos[i].isNaN {
				gda = i
				break
			}
		}
	}
	if gda < 0 {
		return false
	}
	intel := -1
	for _, i := range [3]int{1, 2, 0} {
		if infos[i].isNaN {
			intel = i
			break
		}
	}
	if intel < 0 {
		return false
	}
	return infos[gda].sign != infos[intel].sign || infos[gda].payload != infos[intel].payload
}

type decTestNaNOperand struct {
	isNaN     bool
	signaling bool
	sign      string
	payload   string
}

// parseDecTestNaNOperand extracts the quietized NaN identity of a decTest
// operand literal: sign and payload digits with leading zeros stripped, so
// "-sNaN00" and "-NaN" compare equal after quietization.
func parseDecTestNaNOperand(input string) decTestNaNOperand {
	trimmed := strings.TrimSpace(decTestOperandString(input))
	sign := "+"
	if strings.HasPrefix(trimmed, "-") {
		sign = "-"
		trimmed = trimmed[1:]
	} else {
		trimmed = strings.TrimPrefix(trimmed, "+")
	}
	lower := strings.ToLower(trimmed)
	info := decTestNaNOperand{sign: sign}
	var payload string
	switch {
	case strings.HasPrefix(lower, "snan"):
		info.isNaN = true
		info.signaling = true
		payload = lower[len("snan"):]
	case strings.HasPrefix(lower, "qnan"):
		info.isNaN = true
		payload = lower[len("qnan"):]
	case strings.HasPrefix(lower, "nan"):
		info.isNaN = true
		payload = lower[len("nan"):]
	default:
		return decTestNaNOperand{}
	}
	info.payload = strings.TrimLeft(payload, "0")
	return info
}

func isMinMaxDecTestOperation(op string) bool {
	switch normalizeDecTestOperation(op) {
	case "min", "max", "minmag", "maxmag":
		return true
	default:
		return false
	}
}

func isQuietDecTestNaN(input string) bool {
	trimmed := strings.TrimSpace(decTestOperandString(input))
	trimmed = strings.TrimPrefix(trimmed, "+")
	trimmed = strings.TrimPrefix(trimmed, "-")
	lower := strings.ToLower(trimmed)
	return strings.HasPrefix(lower, "nan") || strings.HasPrefix(lower, "qnan")
}

func isSignalingDecTestNaN(input string) bool {
	trimmed := strings.TrimSpace(decTestOperandString(input))
	trimmed = strings.TrimPrefix(trimmed, "+")
	trimmed = strings.TrimPrefix(trimmed, "-")
	return strings.HasPrefix(strings.ToLower(trimmed), "snan")
}

func hasDecTestNaNPayload(input string) bool {
	for _, r := range input {
		if r >= '0' && r <= '9' {
			return true
		}
	}
	return false
}

func isTaggedToIntegralCase(tc decTestCase) bool {
	op := normalizeDecTestOperation(tc.Operation)
	if op != "tointegral" && op != "tointegralx" {
		return false
	}
	return usesTaggedDecTestLiteral(tc)
}

func usesTaggedDecTestLiteral(tc decTestCase) bool {
	for _, operand := range tc.Operands {
		if strings.Contains(operand, "#") {
			return true
		}
	}
	return strings.Contains(tc.Result, "#")
}

func shouldSkipDecTestFlags(tc decTestCase) bool {
	_, ok := decTestFlagSkipReason(tc)
	return ok
}

func decTestFlagSkipReason(tc decTestCase) (string, bool) {
	if supportsDecTestFlagVerification() {
		return "", false
	}

	op := normalizeDecTestOperation(tc.Operation)
	if op != "add" && op != "subtract" && op != "multiply" && op != "divide" {
		return "", false
	}

	for _, flag := range tc.Flags {
		switch normalizeDecTestFlag(flag) {
		case "clamped", "divisionundefined":
			return "unsupported_flag_" + normalizeDecTestFlag(flag), true
		}
	}
	return "", false
}

func shouldSkipDectestIgnoredOperation(ignoredOperations []string, operation string) bool {
	normalized := normalizeDecTestOperation(operation)
	for _, ignored := range ignoredOperations {
		if normalizeDecTestOperation(ignored) == normalized {
			return true
		}
	}
	return false
}

// testWithDecTestV2 runs the IBM decTest files under testDir.
func testWithDecTestV2(testDir string) error {
	testSuites, err := loadGeneratedDectestRunSuites()
	if err != nil {
		return fmt.Errorf("load generated dectest suites: %w", err)
	}

	totalResults := make(map[string]map[string]int)
	var suiteTotals []decTestSuiteTotals

	// Run each test suite
	for _, suite := range testSuites {
		fmt.Printf("\n=== Running %s Tests ===\n", suite.Name)

		suiteResults := make(map[string]int)
		totalPassed := 0
		totalFailed := 0
		totalSkipped := 0

		for _, generatedFile := range suite.Files {
			testFile := filepath.Join(testDir, filepath.Base(generatedFile))
			base := getBaseName(testFile)

			cases, err := parseDecTestFile(testFile)
			if err != nil {
				fmt.Printf("Failed to parse %s: %v\n", testFile, err)
				continue
			}

			passed := 0
			failed := 0
			skipped := 0

			for _, tc := range cases {
				if _, ok := decTestSkipReason(suite.IgnoredOperations, tc, suite.TestType); ok {
					skipped++
					continue
				}

				err := runDecTestCaseV2(tc, suite.TestType)
				if err != nil {
					if errors.Is(err, errUnsupportedDecTestOperation) || strings.Contains(err.Error(), "unsupported") {
						skipped++
					} else {
						failed++
						if failed < 5 { // Only show first 5 failures per file
							fmt.Printf("FAIL %s: %v\n", tc.ID, err)
						}
					}
				} else {
					passed++
				}
			}

			if passed+failed+skipped > 0 {
				fmt.Printf("%s: %d passed, %d failed, %d skipped (total: %d)\n",
					base, passed, failed, skipped, passed+failed+skipped)
			}

			suiteResults[base] = passed
			totalPassed += passed
			totalFailed += failed
			totalSkipped += skipped
		}

		if totalPassed+totalFailed+totalSkipped > 0 {
			fmt.Printf("Suite %s Total: %d passed, %d failed, %d skipped\n",
				suite.Name, totalPassed, totalFailed, totalSkipped)
		}

		suiteTotals = append(suiteTotals, decTestSuiteTotals{
			Name:    suite.Name,
			Passed:  totalPassed,
			Failed:  totalFailed,
			Skipped: totalSkipped,
		})
		totalResults[suite.Name] = suiteResults
	}

	// Print summary
	fmt.Printf("\n=== New Type System decTest Summary ===\n")
	for suiteName, results := range totalResults {
		fmt.Printf("%s:\n", suiteName)
		for testName, passed := range results {
			fmt.Printf("  %s: %d passed\n", testName, passed)
		}
	}

	return decTestFailureError(suiteTotals)
}

func decTestFailureError(suites []decTestSuiteTotals) error {
	totalFailed := 0
	parts := make([]string, 0, len(suites))

	for _, suite := range suites {
		totalFailed += suite.Failed
		if suite.Failed > 0 {
			parts = append(parts, fmt.Sprintf("%s=%d", suite.Name, suite.Failed))
		}
	}

	if totalFailed == 0 {
		return nil
	}

	return fmt.Errorf("decTest failures detected (%d total): %s", totalFailed, strings.Join(parts, ", "))
}

func compareDecTestFlags(expected []string, actual ExceptionFlags) bool {
	expectedFlags, ok := parseDecTestFlags(expected)
	if !ok {
		return false
	}
	return expectedFlags == actual
}

func parseDecTestFlags(flags []string) (ExceptionFlags, bool) {
	var parsed ExceptionFlags
	for _, flag := range flags {
		switch normalizeDecTestFlag(flag) {
		case "", "none", "noflags":
			continue
		case "inexact":
			parsed |= FlagInexact
		case "underflow":
			parsed |= FlagUnderflow
		case "overflow":
			parsed |= FlagOverflow
		case "divisionbyzero":
			parsed |= FlagDivisionByZero
		case "invalidoperation", "divisionundefined", "divisionimpossible", "insufficientstorage", "conversionsyntax":
			parsed |= FlagInvalidOperation
		case "subnormal":
			parsed |= FlagSubnormal
		case "rounded":
			parsed |= FlagRounded
		case "clamped":
			parsed |= FlagClamped
		default:
			return 0, false
		}
	}
	return parsed, true
}

func normalizeDecTestFlag(flag string) string {
	flag = strings.Trim(flag, "'\"")
	flag = strings.ToLower(flag)
	flag = strings.ReplaceAll(flag, "_", "")
	flag = strings.ReplaceAll(flag, "-", "")
	flag = strings.ReplaceAll(flag, " ", "")
	return flag
}

func splitDecTestFields(input string) []string {
	var fields []string
	var current strings.Builder
	var quote rune

	flush := func() {
		if current.Len() == 0 {
			return
		}
		fields = append(fields, current.String())
		current.Reset()
	}

	for _, r := range input {
		switch {
		case quote != 0:
			current.WriteRune(r)
			if r == quote {
				quote = 0
			}
		case r == '\'' || r == '"':
			current.WriteRune(r)
			quote = r
		case r == ' ' || r == '\t':
			flush()
		default:
			current.WriteRune(r)
		}
	}

	flush()
	return fields
}

